## Code Example

```javascript
// Example: verify signed image (pseudo-code)
const cosign = require('@sigstore/cosign');

async function verifyImage(imageRef, publicKey) {
  try {
    const verification = await cosign.verify(imageRef, { publicKey });
    if (!verification.verified) {
      throw new Error('Image signature verification failed');
    }
    return verification;
  } catch (error) {
    console.error('Verification error:', error);
    throw error;
  }
}
```

